kb = {
    "Eiffel Tower": {"Location": "Paris", "Height": "330m", "BuiltBy": "Gustave Eiffel"},
    "Paris": {"Country": "France", "Pop": "2.1 Million"},
    "France": {"Capital": "Paris", "Currency": "Euro"}
}

def semantic_lookup(entity, relationship):
    # Simulate a Knowledge Graph traversal
    fact = kb.get(entity, {}).get(relationship)
    return f"{entity} {relationship} is {fact}"

print(semantic_lookup("Eiffel Tower", "Location"))
print(semantic_lookup("France", "Currency"))
